const input = $input.first().json;

const REGIONS = {
  ILE_DE_FRANCE: ['75','77','78','91','92','93','94','95'],
  AUVERGNE_RHONE_ALPES: ['01','03','07','15','26','38','42','43','63','69','73','74'],
  BOURGOGNE_FRANCHE_COMTE: ['21','25','39','58','70','71','89','90'],
  BRETAGNE: ['22','29','35','56'],
  CENTRE_VAL_DE_LOIRE: ['18','28','36','37','41','45'],
  CORSE: ['2A','2B'],
  GRAND_EST: ['08','10','51','52','54','55','57','67','68','88'],
  HAUTS_DE_FRANCE: ['02','59','60','62','80'],
  NORMANDIE: ['14','27','50','61','76'],
  NOUVELLE_AQUITAINE: ['16','17','19','23','24','33','40','47','64','79','86','87'],
  OCCITANIE: ['09','11','12','30','31','32','34','46','48','65','66','81','82'],
  PAYS_DE_LA_LOIRE: ['44','49','53','72','85'],
  PROVENCE_ALPES_COTE_AZUR: ['04','05','06','13','83','84'],
  DOM: ['971','972','973','974','976'],
};

const region = input['Région'] || input.region;
const departements = REGIONS[region];

if (!departements) {
  throw new Error(`Région inconnue : ${region}`);
}

const mode = input['Mode recherche'] || input.mode_recherche;
const taille = input['Taille entreprise'] || input.taille || 'TOUTES';
const limitInput = parseInt(input['Limite par page'] || input.limit_par_page) || 500;
const limit = Math.max(100, Math.min(2000, limitInput));

const body = {
  departements: departements,
  taille: taille,
  limit: limit,
  offset: 0
};

if (mode === 'IDCC') {
  const idcc = (input['Code IDCC'] || input.idcc || '').trim();
  if (!idcc) {
    throw new Error('Mode IDCC sélectionné mais aucun code IDCC fourni');
  }
  body.idcc = idcc;
} else if (mode === 'NAF') {
  const naf = (input['Préfixe NAF'] || input.naf || '').trim();
  if (!naf) {
    throw new Error('Mode NAF sélectionné mais aucun préfixe NAF fourni');
  }
  body.naf = naf;
} else {
  throw new Error('Mode de recherche invalide. Choisir IDCC ou NAF.');
}

const enrichissement = input['Enrichissement email'] || input.enrichissement_email;
const enrichirEmail = enrichissement !== 'Non' && enrichissement !== false;

return [{
  json: {
    region: region,
    departements: departements,
    taille: body.taille,
    mode_recherche: mode,
    critere: body.idcc || body.naf,
    limit: body.limit,
    enrichissement_email: enrichirEmail,
    api_body: body,
    sheet_name: `Prospects_${region}_${mode}_${body.idcc || body.naf}_${new Date().toISOString().slice(0,10)}`
  }
}];

const total = $('Count prospects').first().json.total;
const preparation = $('Préparation requête').first().json;
const limit = preparation.limit;
const nbPages = Math.ceil(total / limit);
const allProspects = [];

console.log(`Extraction: ${total} prospects, ${nbPages} pages de ${limit}`);

for (let i = 0; i < nbPages; i++) {
  const body = { ...preparation.api_body, offset: i * limit };

  const response = await fetch('http://172.17.0.1:8042/search/prospects', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body)
  });

  if (!response.ok) {
    throw new Error(`Erreur API page ${i + 1}: ${response.status}`);
  }

  const data = await response.json();

  if (data.results && data.results.length > 0) {
    for (const p of data.results) {
      allProspects.push({
        json: {
          siret: p.siret,
          siren: p.siren,
          denomination: p.denomination || p.denomination_usuelle || p.enseigne || '',
          enseigne: p.enseigne || '',
          naf: p.naf || '',
          code_postal: p.code_postal || '',
          commune: p.commune || '',
          departement: p.departement || '',
          adresse: p.adresse || '',
          tranche_effectif: p.tranche_effectif || '',
          date_creation: p.date_creation || '',
          opco: p.opco || '',
          idcc: p.idcc || '',
          convention_collective: p.convention_collective || '',
          email: '',
          telephone: '',
          site_web: ''
        }
      });
    }
  }

  console.log(`Page ${i + 1}/${nbPages}: ${data.results ? data.results.length : 0} résultats`);

  // Pause 500ms entre chaque page
  if (i < nbPages - 1) {
    await new Promise(resolve => setTimeout(resolve, 500));
  }
}

console.log(`Total extrait: ${allProspects.length} prospects`);
return allProspects;

// PLACEHOLDER — Phase enrichissement email/tel
// Sera implémenté dans V14.1
// Pour l'instant, passe les items tels quels
return $input.all();

const items = $input.all();
const total = items.length;
const preparation = $('Préparation requête').first().json;
const sheetUrl = $('Créer Google Sheet').first().json.spreadsheetUrl || '';

return [{
  json: {
    statut: '✅ Extraction terminée',
    total_prospects: total,
    region: preparation.region,
    critere: `${preparation.mode_recherche}: ${preparation.critere}`,
    taille: preparation.taille,
    sheet_name: preparation.sheet_name,
    google_sheet_url: sheetUrl,
    date_execution: new Date().toISOString()
  }
}];

return [{
  json: {
    statut: '⛔ Aucun prospect trouvé',
    region: $('Préparation requête').first().json.region,
    critere: $('Préparation requête').first().json.mode_recherche + ': ' + $('Préparation requête').first().json.critere,
    taille: $('Préparation requête').first().json.taille
  }
}];
